class Solution:
    def maximumLength(self, nums: List[int]) -> int:
        # Count the number of even and odd numbers
        even_count = 0
        odd_count = 0

        for num in nums:
            if num % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

        # The valid subsequence alternates between even and odd or is all even or all odd
        # The maximum length is the minimum of even_count and odd_count multiplied by 2, or the maximum of even_count and odd_count
        return min(even_count, odd_count) * 2 if min(even_count, odd_count) * 2 > 0 else max(even_count, odd_count)
